# ❌ ANTI-PATTERN: Unbounded reasoning without recovery strategy
class MatchAnalysisAgent:
    def react_loop(self, batting_scenario):
        thought = self.reason(batting_scenario)
        action = self.act(thought)  # No validation
        observation = self.observe(action)

        # Infinite loop risk if action fails
        while not self.is_goal_reached():
            thought = self.reason(observation)
            action = self.act(thought)  # Repeats failed action
            observation = self.observe(action)
        return observation

# ✅ BEST PRACTICE: Bounded reasoning with explicit failure recovery
class CricketMatchAgent:
    def __init__(self, max_iterations=5, backtrack_threshold=2):
        self.max_iterations = max_iterations
        self.backtrack_threshold = backtrack_threshold
        self.action_history = []
        self.failed_attempts = {}

    def react_loop(self, match_state):
        iteration = 0
        while iteration < self.max_iterations and not self.is_goal_reached():
            # Reason with context awareness
            thought = self.reason_about_state(match_state, self.action_history)

            # Select action with fallback
            action = self.select_action(thought)
            if action in self.failed_attempts:
                if self.failed_attempts[action] >= self.backtrack_threshold:
                    action = self.backtrack_and_replan()  # Explicit recovery

            # Observe and validate
            observation = self.act_and_observe(action)

            # Track for recovery
            self.action_history.append((thought, action, observation))
            if not self.is_valid_progress(observation):
                self.failed_attempts[action] = self.failed_attempts.get(action, 0) + 1

            match_state = self.update_context(match_state, observation)
            iteration += 1

        return match_state if self.is_goal_reached() else self.graceful_fallback()

    def select_action(self, thought):
        # Prioritize tools by success rate (cricket_strike > cricket_defend > cricket_appeal)
        available_tools = self.get_tools_for_thought(thought)
        return max(available_tools, key=lambda t: self.tool_success_rate(t))

    def backtrack_and_replan(self):
        # Rewind to last successful state
        last_valid_state = self.action_history[-2] if len(self.action_history) > 1 else None
        return self.reason_about_state(last_valid_state, self.action_history[:-1])

# Real-world production ReAct agent for cricket match analysis
import json
from typing import Any
from datetime import datetime

class MatchAnalysisAgent:
    def __init__(self):
        self.max_steps = 15
        self.context_window = {}
        self.action_history = []

    def observe_match_state(self, match_id: str) -> dict:
        """Fetch current match data from production database"""
        return {
            "match_id": match_id,
            "current_over": 45.3,
            "runs_scored": 287,
            "wickets_lost": 4,
            "required_rate": 8.5,
            "timestamp": datetime.now().isoformat()
        }

    def think_strategy(self, observation: dict) -> str:
        """Reason about next best action"""
        if observation["wickets_lost"] >= 6:
            return "defensive_play_required"
        elif observation["required_rate"] > 10:
            return "aggressive_batting_needed"
        else:
            return "balanced_approach"

    def execute_action(self, strategy: str, match_id: str) -> bool:
        """Execute action with production error handling"""
        try:
            action_record = {
                "strategy": strategy,
                "timestamp": datetime.now().isoformat(),
                "match_id": match_id
            }
            self.action_history.append(action_record)
            return True
        except Exception as e:
            print(f"Action execution failed: {e}")
            return False

    def run_react_loop(self, match_id: str) -> dict:
        """Main ReAct loop with backtracking and context management"""
        step = 0
        success_count = 0

        while step < self.max_steps:
            # OBSERVE: Fetch match state from production system
            observation = self.observe_match_state(match_id)

            # THINK: Reason about strategy
            thought = self.think_strategy(observation)

            # ACT: Execute strategy
            action_success = self.execute_action(thought, match_id)

            if action_success:
                success_count += 1
                self.context_window[f"step_{step}"] = {
                    "observation": observation,
                    "thought": thought,
                    "action_status": "success"
                }
            else:
                # BACKTRACK: Failed action, try alternative
                thought = "fallback_strategy"
                action_success = self.execute_action(thought, match_id)
                self.context_window[f"step_{step}"] = {
                    "observation": observation,
                    "thought": thought,
                    "action_status": "backtracked"
                }

            step += 1

        return {
            "match_id": match_id,
            "total_steps": step,
            "successful_actions": success_count,
            "action_history": self.action_history,
            "final_context": self.context_window
        }

# Production usage
agent = MatchAnalysisAgent()
result = agent.run_react_loop(match_id="IND_vs_AUS_2024")
print(json.dumps(result, indent=2))
